SELECT bs."in.geometry_building_type_recs" AS geometry_building_type_recs, date_trunc('month', date_add('second', -900, ts_pivot.timestamp)) AS timestamp, count(distinct(bs.bldg_id)) AS sample_count, (count(distinct(bs.bldg_id)) * sum(bs.weight)) / CAST(sum(1) AS DECIMAL) AS units_count, sum(1) / CAST(count(distinct(bs.bldg_id)) AS DECIMAL) AS rows_per_sample, sum(ts_pivot."bs__out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption__baseline", sum(CASE WHEN (ts_pivot.bldg_id IS NULL) THEN ts_pivot."bs__out.electricity.total.energy_consumption" ELSE ts_pivot."up__out.electricity.total.energy_consumption" END * bs.weight) AS "electricity.total.energy_consumption__upgrade", sum((coalesce(ts_pivot."bs__out.electricity.total.energy_consumption", 0) - coalesce(CASE WHEN (ts_pivot.bldg_id IS NULL) THEN ts_pivot."bs__out.electricity.total.energy_consumption" ELSE ts_pivot."up__out.electricity.total.energy_consumption" END, 0)) * bs.weight) AS "electricity.total.energy_consumption__savings", sum(ts_pivot."bs__out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption__baseline", sum(CASE WHEN (ts_pivot.bldg_id IS NULL) THEN ts_pivot."bs__out.natural_gas.total.energy_consumption" ELSE ts_pivot."up__out.natural_gas.total.energy_consumption" END * bs.weight) AS "natural_gas.total.energy_consumption__upgrade", sum((coalesce(ts_pivot."bs__out.natural_gas.total.energy_consumption", 0) - coalesce(CASE WHEN (ts_pivot.bldg_id IS NULL) THEN ts_pivot."bs__out.natural_gas.total.energy_consumption" ELSE ts_pivot."up__out.natural_gas.total.energy_consumption" END, 0)) * bs.weight) AS "natural_gas.total.energy_consumption__savings" FROM (SELECT resstock_2024_amy2018_release_2_by_state_vu.bldg_id AS bldg_id, resstock_2024_amy2018_release_2_by_state_vu.timestamp AS timestamp, sum(CASE WHEN (resstock_2024_amy2018_release_2_by_state_vu.upgrade = 0) THEN resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" ELSE NULL END) AS "bs__out.electricity.total.energy_consumption", sum(CASE WHEN (resstock_2024_amy2018_release_2_by_state_vu.upgrade = 1) THEN resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" ELSE NULL END) AS "up__out.electricity.total.energy_consumption", sum(CASE WHEN (resstock_2024_amy2018_release_2_by_state_vu.upgrade = 0) THEN resstock_2024_amy2018_release_2_by_state_vu."out.natural_gas.total.energy_consumption" ELSE NULL END) AS "bs__out.natural_gas.total.energy_consumption", sum(CASE WHEN (resstock_2024_amy2018_release_2_by_state_vu.upgrade = 1) THEN resstock_2024_amy2018_release_2_by_state_vu."out.natural_gas.total.energy_consumption" ELSE NULL END) AS "up__out.natural_gas.total.energy_consumption" FROM resstock_2024_amy2018_release_2_by_state_vu WHERE resstock_2024_amy2018_release_2_by_state_vu.upgrade IN (0, 1) AND resstock_2024_amy2018_release_2_by_state_vu.state IN ('CO', 'WY') GROUP BY resstock_2024_amy2018_release_2_by_state_vu.bldg_id, resstock_2024_amy2018_release_2_by_state_vu.timestamp) AS ts_pivot JOIN resstock_2024_amy2018_release_2_metadata AS bs ON bs.bldg_id = ts_pivot.bldg_id AND bs.upgrade = 0 GROUP BY 1, 2 ORDER BY 1, 2